def solve(n: int, edges: list[list[int]], source: int, target: int, k: int) -> int:
    # Build adjacency list
    graph = [[] for _ in range(n)]
    for u, v, w in edges:
        graph[u].append((v, w))
        graph[v].append((u, w))

    # Binary search on threshold
    left, right = 0, 10**9
    answer = -1

    while left <= right:
        mid = (left + right) // 2
        # Check if there is a valid path with at most k heavy edges
        if is_valid(graph, source, target, k, mid):
            answer = mid
            right = mid - 1
        else:
            left = mid + 1

    return answer

def is_valid(graph, source, target, k, threshold):
    # Dijkstra's algorithm with state (node, num_heavy_edges)
    # We track the minimum number of heavy edges to reach each node
    dist = [[float('inf')] * (k + 1) for _ in range(len(graph))]
    dist[source][0] = 0
    heap = [(0, source, 0)]  # (num_heavy_edges, node, current_threshold)

