                # This is a heavy edge
                new_heavy = heavy + 1
                if new_heavy <= k and dist[neighbor][new_heavy] > heavy + 1:
                    dist[neighbor][new_heavy] = new_heavy
                    heapq.heappush(heap, (new_heavy, neighbor, weight))
